-- ============================================================================
-- Arbor — real taxonomy (Backend §2.1) + Chemicals deal radar (Backend §2.2).
-- Generated by scripts/gen-taxonomy-seed.mjs. Idempotent. Apply after 0005.
-- Non-destructive: demo companies untouched; §2.1 universe lands in a new
-- universe_companies table; §2.2 chemical deals land in companies (sector
-- 'chemicals', which already exists in sector_enum).
-- ============================================================================

-- subsector on deal companies (nullable; chemicals left blank per §1.1).
alter table public.companies add column if not exists subsector text;

-- Monitored company universe (§2.1). No deal stage — sector/subsector as text.
create table if not exists public.universe_companies (
  id         uuid primary key default gen_random_uuid(),
  name       text not null,
  sector     text not null,
  subsector  text,
  created_at timestamptz not null default now(),
  unique (name, sector, subsector)
);
create index if not exists idx_universe_sector on public.universe_companies (sector);
alter table public.universe_companies enable row level security;
drop policy if exists "universe_read" on public.universe_companies;
create policy "universe_read" on public.universe_companies
  for select to authenticated using (true);
grant select on public.universe_companies to authenticated;

create or replace view public.v_universe_counts as
  select sector, subsector, count(*)::int as n
  from public.universe_companies group by sector, subsector;
grant select on public.v_universe_counts to authenticated;
alter view public.v_universe_counts set (security_invoker = on);

-- §2.1 universe (278 companies)
on conflict (name, sector, subsector) do nothing;

-- §2.2 Chemicals deal radar (68 companies) → companies + new_entry history
with ins as (
  returning id, current_stage, name
)
select id, current_stage, 'new_entry', 'analyst_manual', 'manual', 'Added to Chemicals radar — ' || name from ins;
